Emulator.LoadStateAutoHotkeyScript:
; Dolphin loads state with F1 key by default
Send {F1 down}
Sleep 50
Send {F1 up}

Emulator.SaveStateAutoHotkeyScript:
; Dolphin saves state with Shift+F1 keys by default
Send {Shift down}
Sleep 50
Send {F1 down}
Sleep 50
Send {F1 up}
Sleep 50
Send {Shift up}

Emulator.ResetAutoHotkeyScript:
; PLEASE READ: Dolphin does not have a reset key bound by default!
; You must go to Options > Hotkey Settings in Dolphin.
; Bind the R key to the Reset option in order for this to work!
Send {r down}
Sleep 50
Send {r up}

Emulator.AutoHotkeyScript:
Sleep, 5000
 SetKeyDelay, -1, 110
 Send {F11}
 Return 

$Esc::
{
  Send !{f4}
  Return
}

; This section closes 4DO when pressing Escape
$Esc::
{
    WinClose, ahk_exe {{{StartupEXE}}}
}

; This section closes Snes9x when pressing Escape
$Esc::
{
    WinClose, ahk_exe {{{StartupEXE}}}
}

$Esc::
{
    Process, Close, {{{StartupEXE}}}
}

Sleep, 10000
 SetKeyDelay, -1, 110
 Send {F11}
 Return 

