{
  Send !{f4}
  Return
}

$Esc::
{
  Send !{f4}
  Return
}

Sleep, 5000
 SetKeyDelay, -1, 110
 Send {F11}
 Return 

$Esc::
{
  Send !{f4}
  Return
}

$wshell = New-Object -ComObject wscript.shell;
$wshell.AppActivate('RASnes9x.exe')
Sleep 2
$wshell.SendKeys('{ENTER}')
Sleep 1
$wshell.SendKeys('{ESC}%{F}{G}{1}{ESC}')

; This section closes Snes9x when pressing Escape
$Esc::
{
    WinClose, ahk_exe {{{StartupEXE}}}
}

$Esc::
{
  Send !{f4}
  Return
}

$f4::
{
  Send {f5}
  Return
}

$f2::
{
  Send +{f5}
  Return
}

; This section closes nullDC when pressing Escape
$Esc::
{
    WinClose, ahk_exe {{{StartupEXE}}}
}

