; This attempts to bypass any nag screens displayed by MAME when starting a game WinWait, ahk_exe {{{StartupEXE}}},,60 if ErrorLevel return
WinWaitActive,,,30 if ErrorLevel return
Sleep 2000 SetKeyDelay, 125, 50 Send, {space 3}

Emulator.LoadStateAutoHotkeyScript:
; MAME loads state with F7, then slot number keys by default
Send {F7 down}
Sleep 50
Send {F7 up}
Sleep 50
Send {1 down}
Sleep 50
Send {1 up}

Emulator.SaveStateAutoHotkeyScript:
; MAME saves state with Shift+F7, then slot number keys by default
Send {Shift down}
Sleep 50
Send {F7 down}
Sleep 50
Send {F7 up}
Sleep 50
Send {Shift up}
Sleep 50
Send {1 down}
Sleep 50
Send {1 up}

Emulator.ResetAutoHotkeyScript:
; MAME resets game with F3 key by default
Send {F3 down}
Sleep 50
Send {F3 up}

